import React, { useState, useContext } from 'react';
import AdminLayout from '../../components/Layouts/AdminLayout';
import { DataContext } from '../../context/DataContext';
import { formatCurrency } from '../../utils/helpers';

const StaffManager = () => {
  const { staffList, addStaff } = useContext(DataContext);
  const [formData, setFormData] = useState({
    name: '', role: 'Staff', ubi1_percent: 0, ubi2_percent: 0, remuneration: 0
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    addStaff(formData);
    setFormData({ name: '', role: 'Staff', ubi1_percent: 0, ubi2_percent: 0, remuneration: 0 });
  };

  return (
    <AdminLayout>
      <div className="p-4">
        <h2 className="text-2xl font-bold mb-4">Quản lý Nhân sự & Tài chính</h2>
        
        <div className="bg-white p-4 rounded shadow mb-6">
          <h3 className="font-bold mb-3">Thêm nhân sự mới</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <input placeholder="Họ tên" className="border p-2" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />
            
            {/* Yêu cầu 4: Chia mục tài chính */}
            <div className="col-span-1 md:col-span-3 grid grid-cols-3 gap-4 border p-4 bg-gray-50 rounded">
                <h4 className="col-span-3 font-semibold text-gray-700">Thiết lập tài chính:</h4>
                <div>
                    <label className="block text-xs">UBI 1 (%)</label>
                    <input type="number" className="border p-2 w-full" value={formData.ubi1_percent} onChange={e => setFormData({...formData, ubi1_percent: parseFloat(e.target.value)})} />
                </div>
                <div>
                    <label className="block text-xs">UBI 2 (%)</label>
                    <input type="number" className="border p-2 w-full" value={formData.ubi2_percent} onChange={e => setFormData({...formData, ubi2_percent: parseFloat(e.target.value)})} />
                </div>
                <div>
                    <label className="block text-xs">Thù lao (Remuneration)</label>
                    <input type="number" className="border p-2 w-full" value={formData.remuneration} onChange={e => setFormData({...formData, remuneration: parseFloat(e.target.value)})} />
                </div>
            </div>

            <button type="submit" className="bg-green-600 text-white p-2 rounded col-span-1 md:col-span-3">Thêm nhân sự</button>
          </form>
        </div>

        <div className="bg-white p-4 rounded shadow">
            <table className="w-full text-left border-collapse">
                <thead>
                    <tr className="bg-gray-100 border-b">
                        <th className="p-3">Tên</th>
                        <th className="p-3">UBI 1</th>
                        <th className="p-3">UBI 2</th>
                        <th className="p-3">Thù lao cơ bản</th>
                    </tr>
                </thead>
                <tbody>
                    {staffList.map(s => (
                        <tr key={s.id} className="border-b">
                            <td className="p-3">{s.name}</td>
                            <td className="p-3">{s.ubi1_percent}%</td>
                            <td className="p-3">{s.ubi2_percent}%</td>
                            <td className="p-3">{formatCurrency(s.remuneration)}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
      </div>
    </AdminLayout>
  );
};

export default StaffManager;
